const pedidoDB = $json || {};
const trigger = (() => { try { return $("When Executed by Another Workflow").first().json || {}; } catch { return {}; } })();
const datosRest = (() => { try { return $("Obtener Datos Bancarios").first().json || {}; } catch { return {}; } })();

function price(v) {
  return "€" + Number(v || 0).toFixed(2).replace(".", ",");
}

const rawMetodo = String(trigger.metodo || "").toLowerCase().trim();
const metodo = rawMetodo.includes("transfer") ? "transferencia"
  : rawMetodo.includes("bizum") ? "bizum"
  : rawMetodo.includes("online") ? "online"
  : (rawMetodo.includes("tarjeta") || rawMetodo.includes("card")) ? "tarjeta"
  : "efectivo";

let items = [];
try {
  items = typeof pedidoDB.items === "string" ? JSON.parse(pedidoDB.items) : (pedidoDB.items || []);
} catch {
  items = [];
}

const itemsTexto = items.length ? items.map(i => `${Number(i.cantidad || 1)}x ${i.nombre}`).join(", ") : "sin detalle disponible";
const subtotal = Number(pedidoDB.subtotal || 0);
const total = Number(pedidoDB.total || 0);
const costoEnvio = Number(pedidoDB.costo_envio || 0);
const tiempo = pedidoDB.tiempo_estimado ? ` Tiempo estimado: ${pedidoDB.tiempo_estimado}.` : "";

const despachoTexto = String(pedidoDB.tipo_despacho || "") === "delivery"
  ? `Delivery a ${pedidoDB.direccion}. Envío: ${price(costoEnvio)}.${tiempo}`
  : `Retiro en el local${datosRest.direccion ? ` (${datosRest.direccion})` : ""}.${tiempo}`;

// Prominently show order code (Finding 2)
const codigoTexto = pedidoDB.pedido_codigo ? `Tu código de pedido es *${pedidoDB.pedido_codigo}*.` : "";

let instrucciones = "";
if (metodo === "transferencia") {
  // Finding 1: REGISTRADO, not confirmed. Finding 5: include bank details here in WhatsApp channel
  const db = datosRest.datos_bancarios || null;
  instrucciones = `Tu pedido ha sido REGISTRADO y está pendiente de confirmación por el restaurante. Para agilizar el proceso, transfiere ${price(total)}`;
  if (db) {
    instrucciones += " a:
";
    if (db.banco)   instrucciones += `🏦 Banco: ${db.banco}
`;
    if (db.titular) instrucciones += `👤 Titular: ${db.titular}
`;
    if (db.cuenta)  instrucciones += `🔢 Cuenta: ${db.cuenta}
`;
    if (db.alias)   instrucciones += `📲 Alias: ${db.alias}
`;
    instrucciones += "Envíanos el comprobante por aquí y el restaurante confirmará tu pedido.";
  } else {
    instrucciones += " y envíanos el comprobante. El restaurante confirmará tu pedido al verificarlo.";
  }
} else if (metodo === "efectivo") {
  instrucciones = `Pagarás en efectivo por ${price(total)}.`;
} else if (metodo === "tarjeta") {
  instrucciones = `El pago será con tarjeta por ${price(total)}.`;
} else if (metodo === "bizum") {
  instrucciones = `El pago será por Bizum por ${price(total)}.`;
} else {
  instrucciones = `El pago será online por ${price(total)}.`;
}

const resumenItems = `${itemsTexto}. ${despachoTexto} Método de pago: ${metodo}. Subtotal: ${price(subtotal)}. Total: ${price(total)}.`;
const respuesta = [codigoTexto, resumenItems, instrucciones].filter(Boolean).join(" ").replace(/  +/g, " ").trim();

return [{
  json: {
    success: true,
    respuesta_agente: respuesta,
    pedido_id: pedidoDB.id,
    pedido_numero: pedidoDB.pedido_numero,
    pedido_codigo: pedidoDB.pedido_codigo || null,
    total,
    subtotal,
    metodo_pago: metodo,
    estado: pedidoDB.estado || "recibido",
    estado_pago: pedidoDB.estado_pago || "pendiente",
    tipo_despacho: pedidoDB.tipo_despacho || null,
    tiempo_estimado: pedidoDB.tiempo_estimado || null
  }
}];

// Sin pedido activo
return [{
  json: {
    success: false,
    respuesta_agente: 'No encontré un pedido activo para tu número. ¿Quieres hacer un pedido nuevo?',
    pedido_id: null
  }
}];
